2	Matrix Multiplication, with help from cuBLASLt
3	*/
4	#include <assert.h>
5	#include <type_traits>      // std::bool_constant
6	// llmc internal imports
7	#include "cuda_common.h"
8	#include "cuda_utils.cuh"
9	#include "cublas_common.h"
10	// GELU can be either fused (cublasLt) or non-fused (gelu.h)
11	#include "gelu.cuh"
