13	// ----------------------------------------------------------------------------
14	// CUDA kernels
15	
16	template<typename OutFloat, bool UseAuxBuffer>
17	__global__ void matmul_backward_bias_kernel9(OutFloat* dbias, const floatX* dout, int B, int T, int OC,
18	                                             std::bool_constant<UseAuxBuffer>) {
19	    constexpr const int bdx = 4;
20	    constexpr const int bdy = WARP_SIZE / bdx;
21	    assert(blockDim.x == bdx);
22	    assert(blockDim.y == bdy);
23	
24	    int warp_d = (int)threadIdx.x;
25	    int warp_c = (int)threadIdx.y;
26	    int block_d = (int)threadIdx.z;
27	
28	    const int OC_per_warp = bdy * x128::size;  // 64 at BF16
29	
30	    int local_oc = warp_c * x128::size;
31	    int global_oc = blockIdx.x * OC_per_warp + local_oc;
32	
33	    int local_bt = warp_d + bdx * block_d;
34	    int bt_per_block = bdx * blockDim.z;
35	
36	    float accumulators[x128::size];
37	    for (int k = 0; k < x128::size; k++) {
38	        accumulators[k] = 0.0f;
39	    }
40	
41	    if(global_oc < OC) {
42	        // sum up over all bt within registers
43	        for (int idx = blockIdx.y * bt_per_block + local_bt; idx < B * T; idx += gridDim.y * bt_per_block) {
44	            x128 packed_dout = load128(dout + global_oc + idx*OC);
45	            for (int k = 0; k < x128::size; k++) {
46	                accumulators[k] += (float)packed_dout[k];
47	            }
48	        }
49	    }
50	
51	    __shared__ float sub_results[x128::size][WARP_SIZE][bdy];
52	
53	    // reduce within-warp results
54	    for (int k = 0; k < x128::size; k++) {
55	        float v = accumulators[k];
56	        v += __shfl_down_sync(0xffffffff, v, 1, 4);
57	        v += __shfl_down_sync(0xffffffff, v, 2, 4);
58	        if(warp_d == 0) {
59	            sub_results[k][block_d][warp_c] = v;
60	        }
61	    }
62	    __syncthreads();
63	
64	    // block-wide reductions
65	    for (int k = block_d; k < x128::size; k += blockDim.z) {
66	        float a = 0.f;
67	        for (int r = warp_d; r < blockDim.z; r += bdx) {
68	            float v = sub_results[k][r][warp_c];
69	            v += __shfl_down_sync(0xffffffff, v, 1, 4);
70	            v += __shfl_down_sync(0xffffffff, v, 2, 4);
71	            a += v;
72	        }
73	        if(warp_d == 0 && global_oc < OC) {
74	            if constexpr (!UseAuxBuffer) {
75	                dbias[global_oc + k] = (OutFloat)(a + (float)dbias[global_oc + k]);
76	            } else {
77	                dbias[global_oc + k + blockIdx.y * OC] = a;
78	            }
79	        }
80	    }
81	}
82	
83	__global__ void reduce_add_sum_kernel(floatX* dst, const float* src, size_t n, size_t m) {
84	    const size_t idx = (blockIdx.x * blockDim.x + threadIdx.x) * f128::size;
85	    assert(n % x128::size == 0);
86	    if (idx < n) {
87	        f128 acc;
88	        for(int k = 0; k < f128::size; ++k) {
89	            acc[k] = 0.f;
90	        }
91	
92	        for(int l = 0; l < m; ++l) {
93	            f128 s = load128(src + idx + n * l);
94	            for(int k = 0; k < f128::size; ++k) {
95	                acc[k] += s[k];
96	            }
97	        }
98	        for(int k = 0; k < f128::size; ++k) {
99	            dst[idx + k] = (floatX) ((float)dst[idx + k] + acc[k]);
100	        }
101	    }
102	}
