104	// ----------------------------------------------------------------------------
105	// kernel launchers
106	
107	// Wrapper around cublasLtMatmul that is meant to support everything we need in llm.c
108	// https://docs.nvidia.com/cuda/cublas/#cublasltmatmul
109	void matmul_cublaslt(floatX* d, const floatX* a, const floatX* b, const floatX* bias,
110	                     int m, int n, int k, cudaStream_t stream=0, bool transA=true, bool transB=false,
111	                     int batch_count=0, size_t strideA=0, size_t strideB=0, size_t strideOut=0,
112	                     bool accumulate=false, floatX* pre_gelu=NULL, bool backward=false)
113	{
114	    NVTX_RANGE_FN();
115	    bool has_bias = (bias != NULL);
116	    bool has_gelu = (pre_gelu != NULL);
117	
118	    // check alignment (some modes work unaligned but it always best to be aligned for performance)
119	    if(((uintptr_t)a % 16) != 0 || ((uintptr_t)b % 16) != 0 || ((uintptr_t)d % 16) != 0 || ((uintptr_t)bias % 16) != 0) {
120	        printf("All cuBLASLt pointers must be aligned!\n");
121	        exit(EXIT_FAILURE);
122	    }
123	
124	    // create the operation descriptor
125	    cublasLtMatmulDesc_t operationDesc;
126	    cublasCheck(cublasLtMatmulDescCreate(&operationDesc, cublas_compute, CUDA_R_32F));
127	
128	    int returnedResults = 0;
129	    cublasLtMatmulPreference_t preference;
130	    cublasLtMatmulHeuristicResult_t heuristic;
131	
132	    cublasOperation_t opNoTranspose = CUBLAS_OP_N;
133	    cublasOperation_t opTranspose = CUBLAS_OP_T;
134	    cublasCheck(cublasLtMatmulDescSetAttribute(operationDesc, CUBLASLT_MATMUL_DESC_TRANSA, (transA)  ? &opTranspose : &opNoTranspose,   sizeof(opTranspose)));
135	    cublasCheck(cublasLtMatmulDescSetAttribute(operationDesc, CUBLASLT_MATMUL_DESC_TRANSB, (transB) ? &opTranspose   : &opNoTranspose, sizeof(opNoTranspose)));
136	
137	    // define matrix layouts
138	    cublasLtMatrixLayout_t ALayout;
139	    cublasLtMatrixLayout_t BLayout;
140	    cublasLtMatrixLayout_t DLayout;
141	    cublasLtMatrixLayout_t CLayout;
142	    if (transA) {
143	        cublasCheck(cublasLtMatrixLayoutCreate(&ALayout, CUBLAS_LOWP, k, m, k));
144	    } else {
145	        cublasCheck(cublasLtMatrixLayoutCreate(&ALayout, CUBLAS_LOWP, m, k, m));
146	    }
147	    if (transB) {
148	        cublasCheck(cublasLtMatrixLayoutCreate(&BLayout, CUBLAS_LOWP, n, k, n));
149	    } else {
150	        cublasCheck(cublasLtMatrixLayoutCreate(&BLayout, CUBLAS_LOWP, k, n, k));
151	    }
152	    // cuBLASLt requires C in FP8 mode to be BF16 or FP32... (sigh)
153	    cublasCheck(cublasLtMatrixLayoutCreate(&CLayout, (sizeof(floatX) == 1) ? CUDA_R_16BF : CUBLAS_LOWP, m, n, m));
154	    cublasCheck(cublasLtMatrixLayoutCreate(&DLayout, CUBLAS_LOWP, m, n, m));
155	
156	    // Strided Batched GEMM (used for non-flash attention, equivalent to cublasGemmStridedBatchedEx)
157	    if (batch_count) {
158	        cublasCheck(cublasLtMatrixLayoutSetAttribute(ALayout, CUBLASLT_MATRIX_LAYOUT_BATCH_COUNT, &batch_count, sizeof(batch_count)));
159	        cublasCheck(cublasLtMatrixLayoutSetAttribute(BLayout, CUBLASLT_MATRIX_LAYOUT_BATCH_COUNT, &batch_count, sizeof(batch_count)));
160	        cublasCheck(cublasLtMatrixLayoutSetAttribute(CLayout, CUBLASLT_MATRIX_LAYOUT_BATCH_COUNT, &batch_count, sizeof(batch_count)));
161	        cublasCheck(cublasLtMatrixLayoutSetAttribute(DLayout, CUBLASLT_MATRIX_LAYOUT_BATCH_COUNT, &batch_count, sizeof(batch_count)));
162	
163	        cublasCheck(cublasLtMatrixLayoutSetAttribute(ALayout, CUBLASLT_MATRIX_LAYOUT_STRIDED_BATCH_OFFSET, &strideA, sizeof(strideA)));
164	        cublasCheck(cublasLtMatrixLayoutSetAttribute(BLayout, CUBLASLT_MATRIX_LAYOUT_STRIDED_BATCH_OFFSET, &strideB, sizeof(strideB)));
165	        cublasCheck(cublasLtMatrixLayoutSetAttribute(CLayout, CUBLASLT_MATRIX_LAYOUT_STRIDED_BATCH_OFFSET, &strideOut, sizeof(strideOut)));
166	        cublasCheck(cublasLtMatrixLayoutSetAttribute(DLayout, CUBLASLT_MATRIX_LAYOUT_STRIDED_BATCH_OFFSET, &strideOut, sizeof(strideOut)));
167	    }
168	
169	    // create a preference handle with specified max workspace
170	    cublasCheck(cublasLtMatmulPreferenceCreate(&preference));
171	    cublasCheck(cublasLtMatmulPreferenceSetAttribute(preference, CUBLASLT_MATMUL_PREF_MAX_WORKSPACE_BYTES,
172	                                                     &cublaslt_workspace_size, sizeof(cublaslt_workspace_size)));
173	
174	    // setup epilogue and associated pointers for bias & gelu
175	    cublasLtEpilogue_t epilogue;
176	    if (has_gelu) {
177	        int64_t gelu_ld = m; // todo - is this affected by anything else?
178	        cublasCheck(cublasLtMatmulDescSetAttribute(operationDesc, CUBLASLT_MATMUL_DESC_EPILOGUE_AUX_LD, &gelu_ld, sizeof(gelu_ld)));
179	        cublasCheck(cublasLtMatmulDescSetAttribute(operationDesc, CUBLASLT_MATMUL_DESC_EPILOGUE_AUX_POINTER, &pre_gelu, sizeof(pre_gelu)));
180	        if (backward) {
181	            assert(!has_bias); // we shouldn't have any backward matmuls that use both GELU and bias
182	            epilogue = CUBLASLT_EPILOGUE_DGELU;
183	        } else {
184	            epilogue = has_bias ? CUBLASLT_EPILOGUE_GELU_AUX_BIAS : CUBLASLT_EPILOGUE_GELU_AUX;
185	        }
186	    } else if(has_bias){
187	        epilogue = backward ? CUBLASLT_EPILOGUE_BGRADB : CUBLASLT_EPILOGUE_BIAS;
188	    } else {
189	        epilogue = CUBLASLT_EPILOGUE_DEFAULT;
190	    }
191	    cublasCheck(cublasLtMatmulDescSetAttribute(operationDesc, CUBLASLT_MATMUL_DESC_EPILOGUE, &epilogue, sizeof(epilogue)));
192	
193	    if (has_bias) {
194	        // cuBLASLt requires bias in FP8 mode to be BF16... (sigh)
195	        cublasDataType_t bias_data_type = (sizeof(floatX) == 1) ? CUDA_R_16BF : CUBLAS_LOWP; // force BF16 bias for FP8 mode
196	        cublasCheck(cublasLtMatmulDescSetAttribute(operationDesc, CUBLASLT_MATMUL_DESC_BIAS_DATA_TYPE, &bias_data_type, sizeof(bias_data_type)));
197	        cublasCheck(cublasLtMatmulDescSetAttribute(operationDesc, CUBLASLT_MATMUL_DESC_BIAS_POINTER, &bias, sizeof(bias)));
198	    }
199	
200	    // set scale type to FP32 (needs to be FP16 if and only if using CUBLAS_COMPUTE_16F, so it's FP32 even for FP8!)
201	    cublasDataType_t scale_type = CUDA_R_32F;
202	    cublasCheck(cublasLtMatmulDescSetAttribute(operationDesc, CUBLASLT_MATMUL_DESC_SCALE_TYPE, &scale_type, sizeof(scale_type)));
203	
204	    // find a suitable algorithm (cached internally so shouldn't take much CPU time in practice)
205	    cublasLtMatmulAlgoGetHeuristic(cublaslt_handle, operationDesc, ALayout, BLayout, CLayout, DLayout,
206	                                   preference, 1, &heuristic, &returnedResults);
207	    if (returnedResults == 0) {
208	        printf("No cuBLASLt algorithm: m: %d, n: %d, k: %d, bias: %d\n", n, m, k, has_bias);
209	        exit(EXIT_FAILURE);
210	    }
211	
212	    // set whether to accumulate (i.e. D += C) or not - note this isn't considered in algorithm selection (?!)
213	    const float alpha = 1.0f, beta = accumulate ? 1.0f : 0.0f;
214	
215	    // call the matmul
216	    cublasCheck(cublasLtMatmul(cublaslt_handle, operationDesc,
217	                               &alpha, a, ALayout, b, BLayout, &beta, d, CLayout, d, DLayout,
218	                               &heuristic.algo, cublaslt_workspace, cublaslt_workspace_size, stream));
219	
220	    // cleanups
221	    cublasCheck(cublasLtMatmulPreferenceDestroy(preference));
222	    cublasCheck(cublasLtMatmulDescDestroy(operationDesc));
223	    cublasCheck(cublasLtMatrixLayoutDestroy(ALayout));
224	    cublasCheck(cublasLtMatrixLayoutDestroy(BLayout));
225	    cublasCheck(cublasLtMatrixLayoutDestroy(CLayout));
226	    cublasCheck(cublasLtMatrixLayoutDestroy(DLayout));
227	    cudaCheck(cudaGetLastError());
228	}
229	
230	// small wrapper around matmul_cublaslt for the forward pass (keeping historical order of arguments)
231	void matmul_forward_cublaslt(floatX* out,
232	                     floatX* inp, floatX* weight, floatX* bias,
233	                     int B, int T, int C, int OC, cudaStream_t stream,
234	                     floatX* pre_gelu=NULL, int gelu_fusion=1) {
235	    // By default only fuse GELU for H100+ as cuBLAS seems to be inefficient for fused GELU on Ada/Ampere (?)
236	    if (gelu_fusion < 1 && pre_gelu) {
237	        matmul_cublaslt(pre_gelu, weight, inp, bias, OC, B*T, C, stream, true, false, 0, 0, 0, 0, false, NULL, false);
238	        gelu_forward(out, pre_gelu, B*T*OC, stream);
239	    } else {
240	        matmul_cublaslt(out, weight, inp, bias, OC, B*T, C, stream, true, false, 0, 0, 0, 0, false, pre_gelu, false);
241	    }
242	}
243	
244	void matmul_backward(floatX* dinp, floatX* dweight, floatX* dbias,
245	                     floatX* dout, floatX* inp, floatX* weight,
246	                     float* dbias_buffer,
247	                     int B, int T, int C, int OC, cudaStream_t stream,
248	                     floatX* pre_gelu=NULL, int gelu_fusion=1) {
249	    NVTX_RANGE_FN();
250	
251	    // backward to bias, if given, does a +=
252	    if (dbias != NULL) {
253	        // Each warp is responsible for 8 * "x128::size" = 64 OCs at BF16 (OC must be a multiple of 64!)
254	        // Block size is 1024 | 768 threads (32|24 warps) and we reduce those values into 1 at the end
255	
256	        const int block_size = deviceProp.maxThreadsPerMultiProcessor == 1536 ? 768 : 1024;
257	
258	        dim3 block_dim = {4, 8, (unsigned)block_size/WARP_SIZE};
259	        const int OC_per_warp = block_dim.y * x128::size; // 64 at BF16
260	        const int grid_size_x = CEIL_DIV(OC, OC_per_warp); // e.g. 12 horizontal blocks for 768 OCs at BF16
261	        const int grid_size_y = max(1, deviceProp.maxThreadsPerMultiProcessor * deviceProp.multiProcessorCount / (block_size * grid_size_x)); // full GPU!
262	
263	        // If we have enough OC that we don't need cross-block reductions, we can skip the bias_buffer accumulation
264	        // and write results directly to the output.
265	        if(grid_size_y == 1) {
266	            matmul_backward_bias_kernel9<<<dim3(grid_size_x, grid_size_y), block_dim, 0, stream>>>(dbias, dout, B, T, OC, False);
267	            cudaCheck(cudaGetLastError());
268	        } else {
269	            // kernel 9 overwrites temp buffer, so no need to memset
270	            matmul_backward_bias_kernel9<<<dim3(grid_size_x, grid_size_y), block_dim, 0, stream>>>(dbias_buffer, dout, B, T, OC, True);
271	            cudaCheck(cudaGetLastError());
272	            reduce_add_sum_kernel<<<CEIL_DIV(OC, 256 * f128::size), 256, 0, stream>>>(dbias, dbias_buffer, OC, grid_size_y);
273	            cudaCheck(cudaGetLastError());
274	        }
275	        dbias = NULL; // prevent dbias calculation from also being fused in matmul_cublaslt below (if we enabled fusion)
276	    }
277	
278	    // backward to input, uses = in the backward pass (set the gradient)
279	    matmul_cublaslt(dinp, weight, dout, NULL, C, B*T, OC, stream, false, false, 0, 0, 0, 0, false,
280	                    gelu_fusion >= 2 ? pre_gelu : NULL, true);
281	
282	    // backward GELU (if it wasn't fused into the matmul above)
283	    if (gelu_fusion < 2 && pre_gelu) {
284	        gelu_backward_inplace(dinp, pre_gelu, B*T*C, stream);
285	    }
286	
287	    // backward to weight, uses += in the backward pass (accumulate the gradient) by setting alpha=one
288	    matmul_cublaslt(dweight, inp, dout, NULL /*dbias*/, C, OC, B*T, stream, false, true, 0, 0, 0, 0,
289	                    true /* accumulate */, NULL, true);
290	}
